namespace sv_5ed14d97b1d84a54ace4438f8f233375.Models;

// Service contracts
public record JobApplication(PersonalInfo Personal, WorkHistory Work, List<Reference> References, string CoverLetter);
public record PersonalInfo(string FullName, string Email, string Phone, string Address);
public record WorkHistory(List<WorkEntry> Entries);
public record WorkEntry(string Company, string Title, DateTime StartDate, DateTime? EndDate, string Description);
public record Reference(string Name, string Relationship, string Email, string Phone);

public interface IApplicationService
{
    Task<int> SubmitApplicationAsync(JobApplication application);
    Task<bool> ValidateEmailAsync(string email);
}

// Mutable form models for two-way binding
public class PersonalInfoModel
{
    public string FullName { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";
    public string Address { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(FullName)
        && !string.IsNullOrWhiteSpace(Email)
        && !string.IsNullOrWhiteSpace(Phone)
        && !string.IsNullOrWhiteSpace(Address);

    public PersonalInfo ToRecord() => new(FullName.Trim(), Email.Trim(), Phone.Trim(), Address.Trim());
}

public class WorkEntryModel
{
    public string Company { get; set; } = "";
    public string Title { get; set; } = "";
    public DateTime? StartDate { get; set; }
    public DateTime? EndDate { get; set; }
    public bool IsCurrent { get; set; }
    public string Description { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Company)
        && !string.IsNullOrWhiteSpace(Title)
        && StartDate.HasValue;

    public WorkEntry ToRecord() => new(Company.Trim(), Title.Trim(), StartDate!.Value, IsCurrent ? null : EndDate, Description.Trim());
}

public class ReferenceModel
{
    public string Name { get; set; } = "";
    public string Relationship { get; set; } = "";
    public string Email { get; set; } = "";
    public string Phone { get; set; } = "";

    public bool IsValid() =>
        !string.IsNullOrWhiteSpace(Name)
        && !string.IsNullOrWhiteSpace(Relationship)
        && !string.IsNullOrWhiteSpace(Email)
        && !string.IsNullOrWhiteSpace(Phone);

    public Reference ToRecord() => new(Name.Trim(), Relationship.Trim(), Email.Trim(), Phone.Trim());
}

using sv_5ed14d97b1d84a54ace4438f8f233375.Models;

namespace sv_5ed14d97b1d84a54ace4438f8f233375.Services;

public class ApplicationService : IApplicationService
{
    private static int _nextId = 1000;

    public async Task<int> SubmitApplicationAsync(JobApplication application)
    {
        await Task.Delay(1500);
        return Interlocked.Increment(ref _nextId);
    }

    public async Task<bool> ValidateEmailAsync(string email)
    {
        await Task.Delay(500);
        return !string.IsNullOrWhiteSpace(email) && email.Contains('@') && email.Contains('.');
    }
}

.step-indicator {
    position: relative;
}

.step-circle {
    width: 36px;
    height: 36px;
    border-radius: 50%;
    display: flex;
    align-items: center;
    justify-content: center;
    font-weight: bold;
    font-size: 0.9rem;
}

.step-item.dimmed {
    opacity: 0.5;
}

.step-item.completed:hover .step-circle {
    filter: brightness(0.85);
}

@using sv_5ed14d97b1d84a54ace4438f8f233375.Models
@inject IApplicationService ApplicationService

<h4 class="mb-3">Personal Information</h4>

<div class="mb-3">
    <label class="form-label">Full Name <span class="text-danger">*</span></label>
    <input type="text" class="form-control" @bind="Model.FullName" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Email <span class="text-danger">*</span></label>
    <input type="email" class="form-control @(emailError is not null ? "is-invalid" : "")"
           @bind="Model.Email" @bind:event="oninput" />
    @if (emailError is not null)
    {
        <div class="invalid-feedback">@emailError</div>
    }
</div>

<div class="mb-3">
    <label class="form-label">Phone <span class="text-danger">*</span></label>
    <input type="tel" class="form-control" @bind="Model.Phone" @bind:event="oninput" />
</div>

<div class="mb-3">
    <label class="form-label">Address <span class="text-danger">*</span></label>
    <textarea class="form-control" rows="2" @bind="Model.Address" @bind:event="oninput"></textarea>
</div>

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-end">
    <button class="btn btn-primary" @onclick="HandleNext" disabled="@isValidating">
        @if (isValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter] public PersonalInfoModel Model { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }

    private string? emailError;
    private string? validationError;
    private bool isValidating;

    private async Task HandleNext()
    {
        validationError = null;
        emailError = null;

        if (!Model.IsValid())
        {
            validationError = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var isEmailValid = await ApplicationService.ValidateEmailAsync(Model.Email);
            if (!isEmailValid)
            {
                emailError = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync();
        }
        finally
        {
            isValidating = false;
        }
    }
}

@using sv_5ed14d97b1d84a54ace4438f8f233375.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]" Index="index + 1"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => Entries.RemoveAt(index)" />
}

<button class="btn btn-outline-secondary mb-3" @onclick="() => Entries.Add(new WorkEntryModel())">
    + Add Another Position
</button>

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private async Task HandleNext()
    {
        validationError = null;
        if (Entries.Any(e => !e.IsValid()))
        {
            validationError = "Please fill in company, title, and start date for all positions.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_5ed14d97b1d84a54ace4438f8f233375.Models

<h4 class="mb-3">References</h4>
<p class="text-muted">Please provide 2–3 professional references.</p>

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]" Index="index + 1"
                   CanRemove="References.Count > 2"
                   OnRemove="() => References.RemoveAt(index)" />
}

@if (References.Count < 3)
{
    <button class="btn btn-outline-secondary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private void AddReference()
    {
        if (References.Count < 3) References.Add(new ReferenceModel());
    }

    private async Task HandleNext()
    {
        validationError = null;
        if (References.Count < 2)
        {
            validationError = "Please provide at least 2 references.";
            return;
        }
        if (References.Any(r => !r.IsValid()))
        {
            validationError = "Please fill in all fields for each reference.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

@using sv_5ed14d97b1d84a54ace4438f8f233375.Models

<h4 class="mb-3">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">✓ Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6 mb-1"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6 mb-1"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6 mb-1"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6 mb-1"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @for (int i = 0; i < WorkEntries.Count; i++)
            {
                var entry = WorkEntries[i];
                <div class="@(i < WorkEntries.Count - 1 ? "mb-3 border-bottom pb-3" : "")">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @(entry.StartDate?.ToString("MMM yyyy") ?? "—")
                        – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "—")
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0 mt-1">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @for (int i = 0; i < References.Count; i++)
            {
                var r = References[i];
                <div class="@(i < References.Count - 1 ? "mb-2" : "")">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small>@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (submitError is not null)
    {
        <div class="alert alert-danger">@submitError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? submitError;

    private async Task HandleSubmit()
    {
        submitError = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
    }
}

@page "/apply"
@using sv_5ed14d97b1d84a54ace4438f8f233375.Models
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo" OnNext="NextStep" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 3:
            <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo" WorkEntries="workEntries" References="references"
                        CoverLetter="coverLetter" IsSubmitting="isSubmitting" IsSubmitted="isSubmitted"
                        ApplicationId="applicationId" OnEditStep="GoToStep" OnSubmit="Submit" OnBack="PreviousStep" />
            break;
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private bool isSubmitting;
    private bool isSubmitted;
    private int? applicationId;

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 1) currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private async Task Submit()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(currentStep);
            isSubmitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

