@using sv_5ed14d97b1d84a54ace4438f8f233375.Models

<h4 class="mb-3">Work History</h4>

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]" Index="index + 1"
                   CanRemove="Entries.Count > 1"
                   OnRemove="() => Entries.RemoveAt(index)" />
}

<button class="btn btn-outline-secondary mb-3" @onclick="() => Entries.Add(new WorkEntryModel())">
    + Add Another Position
</button>

@if (validationError is not null)
{
    <div class="alert alert-danger">@validationError</div>
}

<div class="d-flex justify-content-between">
    <button class="btn btn-secondary" @onclick="OnBack">Back</button>
    <button class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter] public List<WorkEntryModel> Entries { get; set; } = default!;
    [Parameter] public EventCallback OnNext { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? validationError;

    private async Task HandleNext()
    {
        validationError = null;
        if (Entries.Any(e => !e.IsValid()))
        {
            validationError = "Please fill in company, title, and start date for all positions.";
            return;
        }
        await OnNext.InvokeAsync();
    }
}

