@using sv_5ed14d97b1d84a54ace4438f8f233375.Models

<h4 class="mb-3">Review & Submit</h4>

@if (IsSubmitted)
{
    <div class="alert alert-success text-center py-4">
        <h5 class="mb-2">✓ Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>#@ApplicationId</strong>. We'll be in touch soon.</p>
    </div>
}
else
{
    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(1)">Edit</button>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6 mb-1"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6 mb-1"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6 mb-1"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6 mb-1"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(2)">Edit</button>
        </div>
        <div class="card-body">
            @for (int i = 0; i < WorkEntries.Count; i++)
            {
                var entry = WorkEntries[i];
                <div class="@(i < WorkEntries.Count - 1 ? "mb-3 border-bottom pb-3" : "")">
                    <strong>@entry.Title</strong> at @entry.Company<br />
                    <small class="text-muted">
                        @(entry.StartDate?.ToString("MMM yyyy") ?? "—")
                        – @(entry.IsCurrent ? "Present" : entry.EndDate?.ToString("MMM yyyy") ?? "—")
                    </small>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <p class="mb-0 mt-1">@entry.Description</p>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(3)">Edit</button>
        </div>
        <div class="card-body">
            @for (int i = 0; i < References.Count; i++)
            {
                var r = References[i];
                <div class="@(i < References.Count - 1 ? "mb-2" : "")">
                    <strong>@r.Name</strong> (@r.Relationship)<br />
                    <small>@r.Email · @r.Phone</small>
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <button class="btn btn-link btn-sm p-0" @onclick="() => OnEditStep.InvokeAsync(4)">Edit</button>
        </div>
        <div class="card-body">
            <p class="mb-0" style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    @if (submitError is not null)
    {
        <div class="alert alert-danger">@submitError</div>
    }

    <div class="d-flex justify-content-between">
        <button class="btn btn-secondary" @onclick="OnBack">Back</button>
        <button class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter] public PersonalInfoModel Personal { get; set; } = default!;
    [Parameter] public List<WorkEntryModel> WorkEntries { get; set; } = default!;
    [Parameter] public List<ReferenceModel> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public bool IsSubmitting { get; set; }
    [Parameter] public bool IsSubmitted { get; set; }
    [Parameter] public int? ApplicationId { get; set; }
    [Parameter] public EventCallback<int> OnEditStep { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }
    [Parameter] public EventCallback OnBack { get; set; }

    private string? submitError;

    private async Task HandleSubmit()
    {
        submitError = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            submitError = $"Submission failed: {ex.Message}";
        }
    }
}

@page "/apply"
@using sv_5ed14d97b1d84a54ace4438f8f233375.Models
@rendermode InteractiveServer

<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" CompletedSteps="completedSteps" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 1:
            <PersonalInfoStep Model="personalInfo" OnNext="NextStep" />
            break;
        case 2:
            <WorkHistoryStep Entries="workEntries" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 3:
            <ReferencesStep References="references" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 4:
            <CoverLetterStep @bind-CoverLetter="coverLetter" OnNext="NextStep" OnBack="PreviousStep" />
            break;
        case 5:
            <ReviewStep Personal="personalInfo" WorkEntries="workEntries" References="references"
                        CoverLetter="coverLetter" IsSubmitting="isSubmitting" IsSubmitted="isSubmitted"
                        ApplicationId="applicationId" OnEditStep="GoToStep" OnSubmit="Submit" OnBack="PreviousStep" />
            break;
    }
</div>

@code {
    [Inject] private IApplicationService ApplicationService { get; set; } = default!;

    private int currentStep = 1;
    private HashSet<int> completedSteps = new();

    private PersonalInfoModel personalInfo = new();
    private List<WorkEntryModel> workEntries = [new()];
    private List<ReferenceModel> references = [new(), new()];
    private string coverLetter = "";

    private bool isSubmitting;
    private bool isSubmitted;
    private int? applicationId;

    private void NextStep()
    {
        completedSteps.Add(currentStep);
        currentStep++;
    }

    private void PreviousStep()
    {
        if (currentStep > 1) currentStep--;
    }

    private void GoToStep(int step)
    {
        if (completedSteps.Contains(step) || step == currentStep)
            currentStep = step;
    }

    private async Task Submit()
    {
        isSubmitting = true;
        try
        {
            var application = new JobApplication(
                personalInfo.ToRecord(),
                new WorkHistory(workEntries.Select(e => e.ToRecord()).ToList()),
                references.Select(r => r.ToRecord()).ToList(),
                coverLetter);

            applicationId = await ApplicationService.SubmitApplicationAsync(application);
            completedSteps.Add(currentStep);
            isSubmitted = true;
        }
        finally
        {
            isSubmitting = false;
        }
    }
}

